import chromium from "chrome-aws-lambda"; // serverless Chromium
import puppeteer from "puppeteer-core";   // puppeteer-core works with chromium
import { SoldProperty } from "./soldPropertyScraper";

export async function scrapeSoldProperties(city: string, zip: string): Promise<SoldProperty[]> {
  const url = `https://www.zillow.com/${city}-${zip}/sold/`;

  // Launch headless Chromium for serverless
  const browser = await puppeteer.launch({
    args: chromium.args,
    defaultViewport: chromium.defaultViewport,
    executablePath: await chromium.executablePath,
    headless: chromium.headless,
  });

  const page = await browser.newPage();

  await page.setUserAgent(
    "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"
  );

  // Intercept JSON responses for sold listings
  let soldData: any[] = [];
  page.on("response", async (response) => {
    try {
      const url = response.url();
      if (url.includes("SearchPage")) {
        const json = await response.json();
        const props = json?.cat1?.searchResults?.listResults || [];
        soldData.push(...props);
      }
    } catch (err) {}
  });

  // Navigate to Zillow sold page
  await page.goto(url, { waitUntil: "domcontentloaded", timeout: 60000 });

  // Wait for property cards to load
  await page.waitForSelector("ul.photo-cards li article", { timeout: 60000 });

  // Map the JSON data to SoldProperty
  const results: SoldProperty[] = soldData.map((p: any) => ({
    address: p.address || "",
    soldPrice: Number(p.price?.replace(/[^0-9]/g, "")) || 0,
    soldDate: p.soldDate ? new Date(p.soldDate) : new Date(),
    squareFeet: p.sqft ?? 0,
    yearBuilt: p.yearBuilt ?? 0,
    beds: p.beds ?? 0,
    baths: p.baths ?? 0,
    neighborhoodId: zip,
    distanceMiles: 0,
    hasGarage: p.hasGarage ?? false,
    isBusyStreet: false,
    nearCommercial: false,
    nearMultiFamily: "NONE",
    nearFreeway: false,
  }));

  await browser.close();
  return results;
}
